// ============================================================
// Node: Validate & Extract Input
// v3 — Termasuk level (A1-C2) + user_name
// ============================================================

const data = $input.first().json.body || $input.first().json;

const {
  session_id,
  user_id,
  object_key,
  topic,
  level,
  user_name
} = data;

if (!object_key) {
  throw new Error('object_key wajib diisi. Upload audio ke /upload/presign terlebih dahulu.');
}
if (!session_id) {
  throw new Error('session_id wajib diisi.');
}

return [{
  json: {
    session_id,
    user_id,
    user_name: (user_name || 'Friend').trim(),
    object_key,
    topic:  topic || 'Daily Life',
    level:  (level || 'A1').toUpperCase()
  }
}];

// ============================================================
// Node: Parse LLM Response
// v6 — HANYA parse conversation + pattern_to_use
//      Grammar check dihandle oleh node terpisah (HTTP Request)
// ============================================================

const llmResponse = $input.first().json;
const prevData = $('Extract Transcription').first().json;

let fullText = '';
if (llmResponse.choices && llmResponse.choices[0]) {
  fullText = llmResponse.choices[0].message?.content || '';
}
if (!fullText) throw new Error('LLM tidak mengembalikan response.');

let parsed;
try {
  const cleaned = fullText
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('LLM tidak mengembalikan JSON valid. Raw: ' + fullText.slice(0, 200));
}

return [{
  json: {
    ...prevData,
    conversation_text: parsed.conversation || '',
    pattern_to_use:    parsed.pattern_to_use || 'NONE',
    full_llm_response: fullText
  }
}];

// ============================================================
// Node: Check if Correction Exists
// v6 — ambil data dari Parse Grammar Response
// ============================================================

const data = $('Parse Grammar Response').first().json;

if (data.correction && data.correction.has_error) {
  return [{ json: data }];
}
return [];

// ============================================================
// Node: Build Final Response v9
// Sequential TTS flow:
//   1. correction_audio_url (kalau has_error = true)
//   2. audio_url (conversation — selalu ada)
// ============================================================

const grammarData  = $('Parse Grammar Response').first().json;
const whisperNode  = $('Extract Transcription').first().json;

const sessionId    = grammarData.session_id;
const hasError     = grammarData.correction && grammarData.correction.has_error === true;

const audioUrl           = `http://localhost:9002/audio-uploads/audio/${sessionId}.mp3`;
const correctionAudioUrl = hasError
  ? `http://localhost:9002/audio-uploads/audio/${sessionId}_correction.mp3`
  : null;

// Debug log (tampil di n8n execution output)
console.log('[BuildFinalResponse] session_id:', sessionId);
console.log('[BuildFinalResponse] has_error:', hasError);
console.log('[BuildFinalResponse] correction_audio_url:', correctionAudioUrl);
console.log('[BuildFinalResponse] audio_url:', audioUrl);
console.log('[BuildFinalResponse] correction obj:', JSON.stringify(grammarData.correction));

return [{
  json: {
    success:                 true,
    session_id:              sessionId,
    user_text:               whisperNode.user_text || 'Audio processed',
    conversation:            grammarData.conversation_text,
    pattern_to_use:          grammarData.pattern_to_use || 'NONE',
    correction:              grammarData.correction,
    audio_url:               audioUrl,
    audio_format:            'mp3',
    correction_audio_url:    correctionAudioUrl,
    correction_audio_format: 'mp3'
  }
}];

// ============================================================
// Node: Build Session Response
// v2 — Level-aware + Vocab topic support
// ============================================================

const dbResult = $input.first().json;
const body = $('Webhook — POST /session/start').first().json.body;

const rawTopic = body.topic || 'Daily Life';
const userName = (body.user_name || 'Friend').trim();
const level = (body.level || 'A1').toUpperCase();

// Deteksi apakah ini mode Vocab Practice
const isVocab = rawTopic.startsWith('Practice vocabulary:');
const vocabWords = isVocab ? rawTopic.replace('Practice vocabulary:', '').trim() : '';

// Normalized topic key untuk lookup
const topic = isVocab ? 'Vocab' : rawTopic;

// Level descriptions untuk opening message
const levelDescriptions = {
  'A1': 'absolute beginner',
  'A2': 'elementary',
  'B1': 'intermediate',
  'B2': 'upper-intermediate',
  'C1': 'advanced',
  'C2': 'proficient/native-like'
};
const levelDesc = levelDescriptions[level] || 'beginner';

// Opening messages berdasarkan topik
const openingMessages = {
  'Daily Life':            `Hi! Let's talk about daily life. What does your typical morning look like?`,
  'Food & Cooking':        `Hey there! I love talking about food. What's your favorite dish to eat or cook?`,
  'Travel & Places':       `Let's talk about travel! Have you been to any interesting places recently?`,
  'Work & Career':         `Great topic! Tell me about your work. What do you do for a living?`,
  'Hobbies & Interests':   `Fun topic! What do you like to do in your free time?`,
  'Technology':            `Tech is always exciting! Are you into any new gadgets or apps lately?`,
  'Movies & Entertainment':`I love movies! What kind of films or shows are you into?`,
  'Health & Fitness':      `Great choice! Do you have any workout routine or health habits you follow?`,
  'Family & Relationships':`Family is important! Tell me a little about your family.`,
  'Current Events':        `Let's talk about what's happening in the world. Anything interesting you've noticed lately?`,
  'Vocab':                 `Great! Let's practice your target vocabulary: **${vocabWords}**. I'll help you use each word naturally in conversation. Can you try using one of these words in a sentence right now?`
};

// Pattern awal per topik
const openingPatterns = {
  'Daily Life':            'I wake up at [time]. OR My morning is [adjective].',
  'Food & Cooking':        'My favorite food is [food]. OR I like to eat [food].',
  'Travel & Places':       'Yes, I went to [place]. OR No, I did not travel recently.',
  'Work & Career':         'I am a [job]. OR I work at [place].',
  'Hobbies & Interests':   'I like to [activity]. OR My hobby is [activity].',
  'Technology':            'Yes, I use [gadget/app]. OR No, I do not use new gadgets.',
  'Movies & Entertainment':'I like [genre] movies. OR My favorite show is [name].',
  'Health & Fitness':      'Yes, I [activity] every day. OR No, I do not exercise much.',
  'Family & Relationships':'I have [number] family members. OR My family is [adjective].',
  'Current Events':        'I heard about [topic]. OR I think [topic] is interesting.',
  'Vocab':                 `[vocab word] means [meaning]. OR I use [vocab word] when [situation].`
};

const openingMessage = openingMessages[topic] || `Hi! Let's have a conversation in English. How are you today?`;
const patternToUse   = openingPatterns[topic]  || 'I think... OR I like...';

return [
  {
    json: {
      success:         true,
      session_id:      dbResult.id,
      user_id:         dbResult.user_id,
      topic:           dbResult.topic,
      level,
      level_desc:      levelDesc,
      is_vocab:        isVocab,
      vocab_words:     vocabWords,
      opening_message: openingMessage,
      pattern_to_use:  patternToUse
    }
  }
];

// ============================================================
// Node: Build Corrections Response
// ============================================================

const items = $input.all();
const corrections = items.map(item => item.json);

return [
  {
    json: {
      success: true,
      session_id: $('Webhook — GET /corrections/:session_id').first().json.params.session_id,
      total: corrections.length,
      corrections
    }
  }
];

// ============================================================
// Node: Extract Transcription
// Ambil hasil Whisper + gabungkan dengan metadata dari upstream
// ============================================================

const whisperResponse = $input.first().json;
const prevData = $('Fetch Audio from MinIO').first().json;  // updated reference

let transcribedText = '';
if (whisperResponse.text) {
  transcribedText = whisperResponse.text.trim();
} else if (whisperResponse.data) {
  transcribedText = whisperResponse.data.trim();
} else if (typeof whisperResponse === 'string') {
  transcribedText = whisperResponse.trim();
}

if (!transcribedText) {
  throw new Error('Whisper gagal transkrip. Response: ' + JSON.stringify(whisperResponse));
}

return [{
  json: {
    ...prevData,
    user_text: transcribedText
  }
}];

// ============================================================
// Node: Build Messages with History
// v6 — Level-aware (A1-C2) + Vocab mode support
// ============================================================

const inputData = $('Extract Transcription').first().json;

const rawTopic = (inputData.topic || 'Daily Life').trim();
const level    = (inputData.level  || 'A1').toUpperCase();
const userName = (inputData.user_name || 'Friend').trim();

const historyRows = $input.all();

let latestUserText = (inputData.user_text || '').trim();
if (!latestUserText) {
  latestUserText = "(User said nothing or audio was unclear)";
}

const allHistory = historyRows
  .map(r => r.json)
  .filter(r => r.role && r.message);

let historySlice = allHistory.slice(-18);
if (historySlice.length % 2 !== 0) {
  historySlice = historySlice.slice(1);
}

// Level ke CEFR instructions
const levelInstructions = {
  'A1': 'Use only the simplest Present Simple sentences. Max 6 words per sentence. Vocabulary: extremely basic (colors, numbers, family, food). One very simple question at a time.',
  'A2': 'Use Present Simple and Present Continuous. Short sentences (8 words max). Basic everyday vocabulary. Ask simple questions about daily routines.',
  'B1': 'Use a variety of tenses (Past Simple, Present Perfect, Future). Medium sentences. Everyday vocabulary with some idioms. Ask open-ended questions.',
  'B2': 'Use complex sentences with subordinate clauses. Mix of tenses including conditionals. Wider vocabulary, phrasal verbs. Thought-provoking questions.',
  'C1': 'Use sophisticated sentence structures. Advanced vocabulary, collocations, idiomatic expressions. Nuanced questions requiring detailed answers.',
  'C2': 'Use near-native complexity. Highly idiomatic, nuanced, culturally aware language. Engage in abstract discussion and debate.'
};
const levelInstruction = levelInstructions[level] || levelInstructions['A1'];

// Detect Vocab mode
const isVocab = rawTopic.startsWith('Practice vocabulary:');
const vocabWords = isVocab ? rawTopic.replace('Practice vocabulary:', '').trim() : '';
const displayTopic = isVocab ? 'Vocabulary Practice' : rawTopic;

// Build system prompt
let systemPrompt;

if (isVocab) {
  systemPrompt = `You are a friendly AI English tutor for an Indonesian student named ${userName} at CEFR level ${level}.

THE STUDENT IS PRACTICING THESE TARGET VOCABULARY WORDS: "${vocabWords}"

YOUR MISSION:
- Naturally weave the target vocabulary words into the conversation one or two at a time.
- Encourage the student to use those words in their answers.
- Gently guide them if they haven't used a word yet, e.g. "Can you try to use the word **resilient** in a sentence?"
- Bold the target vocabulary words wherever they appear: **ubiquitous**, **resilient**.

LANGUAGE LEVEL RULES FOR ${level}:
${levelInstruction}

OUTPUT: Strictly valid JSON only. No markdown, no backticks.
{
  "conversation": "Your response + question encouraging use of a target vocab word with **bold** formatting.",
  "pattern_to_use": "Try: '[vocab word] means... OR In my life, [vocab word] is...'."
}`;
} else {
  systemPrompt = `You are a friendly, enthusiastic AI English tutor for an Indonesian student named ${userName} at CEFR level ${level}.

THE CURRENT CONVERSATION TOPIC IS: "${displayTopic}"
You must base your comments and questions strictly on this topic.

LANGUAGE LEVEL RULES FOR ${level}:
${levelInstruction}

GENERAL RULES:
1. Be encouraging, warm, and highly conversational.
2. Ask exactly 1 NEW question relevant to the topic. Bold key vocabulary like **apple**.
3. Do NOT focus on cliche examples unless explicitly brought up by the student.
4. Never repeat the same question twice in a row.

OUTPUT: Strictly valid JSON only. No markdown, no backticks.
{
  "conversation": "Your level-appropriate response + your next topic-related question with **bold** vocabulary.",
  "pattern_to_use": "Simple answer template or options for your question."
}`;
}

const messages = [
  { role: "system", content: systemPrompt },
  ...historySlice.map(row => ({ role: row.role, content: row.message })),
  { role: "user", content: latestUserText }
];

const requestBody = JSON.stringify({
  model: "google/gemini-2.5-flash-lite",
  max_tokens: 350,
  messages: messages,
  temperature: 1.0,
  response_format: { type: "json_object" }
});

return [{
  json: {
    ...inputData,
    user_text: latestUserText,
    llm_request_body: requestBody,
    history_length: historySlice.length / 2
  }
}];

// ============================================================================
// VANILLA JAVASCRIPT SHA-256 & HMAC IMPLEMENTATION (Sandbox-Friendly)
// ============================================================================
function sha256_pure(ascii) {
  function rightRotate(value, amount) { return (value >>> amount) | (value << (32 - amount)); }
  var mathPow = Math.pow, maxWord = mathPow(2, 32), result = '', words = [];
  var asciiLength = ascii.length, hash = [], k = [], primeCounter = 0, isPrime = {};
  for (var i = 2; primeCounter < 64; i++) {
    if (!isPrime[i]) {
      for (var j = i * i; j < 312; j += i) { isPrime[j] = true; }
      if (primeCounter < 8) hash[primeCounter] = (mathPow(i, .5) * maxWord) | 0;
      k[primeCounter] = (mathPow(i, 1 / 3) * maxWord) | 0; primeCounter++;
    }
  }
  ascii += '\x80'; while (ascii.length % 64 - 56) ascii += '\x00';
  for (var i = 0; i < ascii.length; i++) { var j = ascii.charCodeAt(i); words[i >> 2] |= j << (24 - (i % 4) * 8); }
  words[words.length] = ((asciiLength * 8) / maxWord) | 0; words[words.length] = (asciiLength * 8) | 0;
  for (var j = 0; j < words.length; j += 16) {
    var w = words.slice(j, j + 16), oldHash = hash.slice(0);
    for (var i = 0; i < 64; i++) {
      if (i >= 16) {
        var w15 = w[i - 15], w2 = w[i - 2];
        var s0 = rightRotate(w15, 7) ^ rightRotate(w15, 18) ^ (w15 >>> 3);
        var s1 = rightRotate(w2, 17) ^ rightRotate(w2, 19) ^ (w2 >>> 10);
        w[i] = (w[i - 16] + s0 + w[i - 7] + s1) | 0;
      }
      var ch = (hash[4] & hash[5]) ^ (~hash[4] & hash[6]), maj = (hash[0] & hash[1]) ^ (hash[0] & hash[2]) ^ (hash[1] & hash[2]);
      var s0_h = rightRotate(hash[0], 2) ^ rightRotate(hash[0], 13) ^ rightRotate(hash[0], 22), s1_h = rightRotate(hash[4], 6) ^ rightRotate(hash[4], 11) ^ rightRotate(hash[4], 25);
      var t1 = (hash[7] + s1_h + ch + k[i] + (w[i] || 0)) | 0, t2 = (s0_h + maj) | 0;
      hash = [(t1 + t2) | 0].concat(hash); hash[4] = (hash[4] + t1) | 0; hash.length = 8;
    }
    for (var i = 0; i < 8; i++) hash[i] = (hash[i] + oldHash[i]) | 0;
  }
  for (var i = 0; i < 8; i++) result += (('00000000' + (hash[i] >>> 0).toString(16)).slice(-8));
  return result;
}

function hexToBytes(hex) { var bytes = []; for (var c = 0; c < hex.length; c += 2) bytes.push(parseInt(hex.substr(c, 2), 16)); return bytes; }
function stringToBytes(str) { var bytes = []; for (var i = 0; i < str.length; i++) bytes.push(str.charCodeAt(i) & 0xFF); return bytes; }
function hmac_sha256_pure(key, data, returnBytes = false) {
  var bKey = (typeof key === 'string') ? stringToBytes(key) : key, bData = (typeof data === 'string') ? stringToBytes(data) : data;
  if (bKey.length > 64) bKey = hexToBytes(sha256_pure(String.fromCharCode.apply(null, bKey)));
  while (bKey.length < 64) bKey.push(0);
  var ipad = [], opad = []; for (var i = 0; i < 64; i++) { ipad.push(bKey[i] ^ 0x36); opad.push(bKey[i] ^ 0x5C); }
  var innerData = ipad.concat(bData), innerHashHex = sha256_pure(String.fromCharCode.apply(null, innerData));
  var outerData = opad.concat(hexToBytes(innerHashHex)), outerHashHex = sha256_pure(String.fromCharCode.apply(null, outerData));
  return returnBytes ? hexToBytes(outerHashHex) : outerHashHex;
}

function getSignatureKeyPure(key, dateStamp, regionName, serviceName) {
  const kDate = hmac_sha256_pure('AWS4' + key, dateStamp, true);
  const kRegion = hmac_sha256_pure(kDate, regionName, true);
  const kService = hmac_sha256_pure(kRegion, serviceName, true);
  return hmac_sha256_pure(kService, 'aws4_request', true);
}

// ============================================================================
// MAIN GENERATOR LOGIC (STRICT FIXED FOR BROWSER PUT)
// ============================================================================
const bucket = 'audio-uploads';
const accessKey = 'isi_bebas_min3karakter'; 
const secretKey = 'isi_bebas_min8karakter'; 
const region = 'us-east-1';

function buildBrowserPresignedUrl(method, objectKey, expiresIn = 900) {
  const date = new Date();
  const amzDate = date.toISOString().replace(/[:-]/g, '').split('.')[0] + 'Z';
  const dateStamp = amzDate.substr(0, 8);
  const credential = `${accessKey}/${dateStamp}/${region}/s3/aws4_request`;

  const signatureHost = 'localhost:9002';
  const baseEndpoint = 'http://localhost:9002';

  const qsParams = [
    ['X-Amz-Algorithm', 'AWS4-HMAC-SHA256'],
    ['X-Amz-Credential', credential],
    ['X-Amz-Date', amzDate],
    ['X-Amz-Expires', String(expiresIn)],
    ['X-Amz-SignedHeaders', 'host'],
  ];

  // Susun query string terurut secara alfabetis
  const qs = qsParams.map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`).join('&');

  // Perbaikan struktur Newline (\n) Canonical Request AWS V4 yang sangat presisi
  const canonicalRequest = [
    method,
    '/' + bucket + '/' + objectKey,
    qs,
    'host:' + signatureHost,  // Tanpa manual \n tambahan di ujung string, biarkan join('\n') yang bekerja
    '',                       // Spasi kosong untuk memisahkan daftar Signed Headers dengan Canonical Headers
    'host',
    'UNSIGNED-PAYLOAD'
  ].join('\n');

  const stringToSign = [
    'AWS4-HMAC-SHA256',
    amzDate,
    `${dateStamp}/${region}/s3/aws4_request`,
    sha256_pure(canonicalRequest)
  ].join('\n');

  const signingKey = getSignatureKeyPure(secretKey, dateStamp, region, 's3');
  const signature = hmac_sha256_pure(signingKey, stringToSign);

  return `${baseEndpoint}/${bucket}/${objectKey}?${qs}&X-Amz-Signature=${signature}`;
}

// --- EXECUTION ---
const body = $input.first().json.body || {};
const session_id = body.session_id || 'default-session';

const timestamp = Date.now();
const randomString = Math.random().toString(36).substring(7);
const objectKey = `audio/${session_id}/${timestamp}_${randomString}.webm`;

const presignedUrlForBrowser = buildBrowserPresignedUrl('PUT', objectKey, 900);

return [{
  json: {
    success: true,
    presigned_url: presignedUrlForBrowser,
    object_key: objectKey,
    bucket_name: bucket
  }
}];

// ============================================================
// Pure JS SHA-256 & HMAC-SHA256 — zero dependencies
// Verified correct against Node.js crypto module
// ============================================================
function _sha256Bytes(inputBytes) {
  const H=[0x6a09e667,0xbb67ae85,0x3c6ef372,0xa54ff53a,0x510e527f,0x9b05688c,0x1f83d9ab,0x5be0cd19];
  const K=[0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2];
  const bytes=[...inputBytes];
  const origLen=bytes.length;
  bytes.push(0x80);
  while(bytes.length%64!==56)bytes.push(0);
  const bitLen=origLen*8;
  bytes.push(0,0,0,0,(bitLen>>>24)&0xff,(bitLen>>>16)&0xff,(bitLen>>>8)&0xff,bitLen&0xff);
  const h=[...H];
  for(let i=0;i<bytes.length;i+=64){
    const w=[];
    for(let j=0;j<16;j++)w[j]=((bytes[i+j*4]<<24)|(bytes[i+j*4+1]<<16)|(bytes[i+j*4+2]<<8)|bytes[i+j*4+3])>>>0;
    for(let j=16;j<64;j++){const s0=(((w[j-15]>>>7)|(w[j-15]<<25))^((w[j-15]>>>18)|(w[j-15]<<14))^(w[j-15]>>>3))>>>0;const s1=(((w[j-2]>>>17)|(w[j-2]<<15))^((w[j-2]>>>19)|(w[j-2]<<13))^(w[j-2]>>>10))>>>0;w[j]=(w[j-16]+s0+w[j-7]+s1)>>>0;}
    let a=h[0],b=h[1],c=h[2],d=h[3],e=h[4],f=h[5],g=h[6],hh=h[7];
    for(let j=0;j<64;j++){const S1=(((e>>>6)|(e<<26))^((e>>>11)|(e<<21))^((e>>>25)|(e<<7)))>>>0;const ch=((e&f)^((~e>>>0)&g))>>>0;const tmp1=(hh+S1+ch+K[j]+w[j])>>>0;const S0=(((a>>>2)|(a<<30))^((a>>>13)|(a<<19))^((a>>>22)|(a<<10)))>>>0;const maj=((a&b)^(a&c)^(b&c))>>>0;const tmp2=(S0+maj)>>>0;hh=g;g=f;f=e;e=(d+tmp1)>>>0;d=c;c=b;b=a;a=(tmp1+tmp2)>>>0;}
    h[0]=(h[0]+a)>>>0;h[1]=(h[1]+b)>>>0;h[2]=(h[2]+c)>>>0;h[3]=(h[3]+d)>>>0;h[4]=(h[4]+e)>>>0;h[5]=(h[5]+f)>>>0;h[6]=(h[6]+g)>>>0;h[7]=(h[7]+hh)>>>0;
  }
  return h.map(v=>v.toString(16).padStart(8,'0')).join('');
}
function _strToBytes(s){const b=[];for(let i=0;i<s.length;i++){const c=s.charCodeAt(i);if(c<128)b.push(c);else if(c<2048){b.push((c>>6)|192);b.push((c&63)|128);}else{b.push((c>>12)|224);b.push(((c>>6)&63)|128);b.push((c&63)|128);}}return b;}
function _hexToBytes(hex){const b=[];for(let i=0;i<hex.length;i+=2)b.push(parseInt(hex.slice(i,i+2),16));return b;}
function sha256Hex(input){return _sha256Bytes(typeof input==='string'?_strToBytes(input):input);}
function hmacSha256(keyInput,msgInput){
  let key=typeof keyInput==='string'?_strToBytes(keyInput):[...keyInput];
  const msg=typeof msgInput==='string'?_strToBytes(msgInput):[...msgInput];
  if(key.length>64)key=_hexToBytes(_sha256Bytes(key));
  while(key.length<64)key.push(0);
  const opad=key.map(b=>(b^0x5c)&0xff);
  const ipad=key.map(b=>(b^0x36)&0xff);
  const innerBytes=_hexToBytes(_sha256Bytes([...ipad,...msg]));
