// Parse hasil grammar check dari HTTP Request node
// ============================================================

const grammarLLM = $input.first().json;
const prevData = $('Prepare Grammar Request').first().json;

// Default: tidak ada koreksi
let correction = { has_error: false, wrong: 'NONE', right: 'NONE', reason: 'NONE' };

// Jika skip_grammar (user_text kosong), langsung return
if (prevData.skip_grammar) {
  return [{ json: { ...prevData, correction } }];
}

try {
  let rawText = '';
  if (grammarLLM.choices && grammarLLM.choices[0]) {
    rawText = grammarLLM.choices[0].message?.content || '{}';
  }

  const cleaned = rawText
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  const g = JSON.parse(cleaned);

  let hasError = g.has_error === true;
  const wrong  = (g.wrong  || 'NONE').trim();
  const right  = (g.right  || 'NONE').trim();
  const reason = (g.reason || 'NONE').trim();

  // Validasi 1: batalkan jika wrong == right (koreksi identik)
  if (hasError && wrong !== 'NONE' && right !== 'NONE') {
    const wc = wrong.toLowerCase().replace(/[^a-z0-9\s]/g, '').trim();
    const rc = right.toLowerCase().replace(/[^a-z0-9\s]/g, '').trim();
    if (wc === rc) hasError = false;
  }

  // Validasi 2: batalkan jika field penting NONE
  if (hasError && (wrong === 'NONE' || right === 'NONE')) hasError = false;

  correction = {
    has_error: hasError,
    wrong:  hasError ? wrong  : 'NONE',
    right:  hasError ? right  : 'NONE',
    reason: hasError ? reason : 'NONE'
  };

} catch (e) {
  // Parse gagal → tidak ada koreksi (safe fallback)
  correction = { has_error: false, wrong: 'NONE', right: 'NONE', reason: 'NONE' };
}

return [{ json: { ...prevData, correction } }];

// ============================================================
// Node: Prepare Correction Text
// Siapkan teks koreksi untuk TTS dengan kalimat pembuka.
// Format: "Hmm, kurang tepat. Seharusnya: [right]. [reason]"
// ============================================================

const data = $('Parse Grammar Response').first().json;
const correction = data.correction || {};
const hasError = correction.has_error === true
  && correction.right
  && correction.right !== 'NONE';

let ttsText = 'ok'; // placeholder jika tidak ada error

if (hasError) {
  // Strip markdown bold (**word**) agar TTS tidak membaca tanda bintang
  const stripBold = (str) => (str || '')
    .replace(/\*\*(.*?)\*\*/g, '$1')
    .replace(/\r?\n+/g, ' ')
    .replace(/[\x00-\x1F\x7F]/g, '')
    .replace(/\s{2,}/g, ' ')
    .trim();

  const rightText = stripBold(correction.right);
  const reasonText = stripBold(correction.reason);

  // Kalimat pembuka + koreksi yang benar + alasan singkat
  // Sesuaikan kalimat pembuka sesuai selera Anda di sini
  ttsText = `Hmm, kurang tepat. Seharusnya kamu mengucapkan: ${rightText}. ${reasonText}`;

  // Batasi panjang agar tidak terlalu panjang dibacakan
  if (ttsText.length > 300) ttsText = ttsText.slice(0, 300);
}

return [{
  json: {
    ...data,
    tts_correction_text: ttsText,
    skip_correction_tts: !hasError,
    correction_has_error: hasError
  }
}];

