// --- HELPER FUNCTIONS ---
function _sha256Bytes(inputBytes) {
  const H=[0x6a09e667,0xbb67ae85,0x3c6ef372,0xa54ff53a,0x510e527f,0x9b05688c,0x1f83d9ab,0x5be0cd19];
  const K=[0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2];
  const bytes=[...inputBytes];
  const origLen=bytes.length;
  bytes.push(0x80);
  while(bytes.length%64!==56)bytes.push(0);
  const bitLen=origLen*8;
  bytes.push(0,0,0,0,(bitLen>>>24)&0xff,(bitLen>>>16)&0xff,(bitLen>>>8)&0xff,bitLen&0xff);
  const h=[...H];
  for(let i=0;i<bytes.length;i+=64){
    const w=[];
    for(let j=0;j<16;j++)w[j]=((bytes[i+j*4]<<24)|(bytes[i+j*4+1]<<16)|(bytes[i+j*4+2]<<8)|bytes[i+j*4+3])>>>0;
    for(let j=16;j<64;j++){const s0=(((w[j-15]>>>7)|(w[j-15]<<25))^((w[j-15]>>>18)|(w[j-15]<<14))^(w[j-15]>>>3))>>>0;const s1=(((w[j-2]>>>17)|(w[j-2]<<15))^((w[j-2]>>>19)|(w[j-2]<<13))^(w[j-2]>>>10))>>>0;w[j]=(w[j-16]+s0+w[j-7]+s1)>>>0;}
    let a=h[0],b=h[1],c=h[2],d=h[3],e=h[4],f=h[5],g=h[6],hh=h[7];
    for(let j=0;j<64;j++){const S1=(((e>>>6)|(e<<26))^((e>>>11)|(e<<21))^((e>>>25)|(e<<7)))>>>0;const ch=((e&f)^((~e>>>0)&g))>>>0;const tmp1=(hh+S1+ch+K[j]+w[j])>>>0;const S0=(((a>>>2)|(a<<30))^((a>>>13)|(a<<19))^((a>>>22)|(a<<10)))>>>0;const maj=((a&b)^(a&c)^(b&c))>>>0;const tmp2=(S0+maj)>>>0;hh=g;g=f;f=e;e=(d+tmp1)>>>0;d=c;c=b;b=a;a=(tmp1+tmp2)>>>0;}
    h[0]=(h[0]+a)>>>0;h[1]=(h[1]+b)>>>0;h[2]=(h[2]+c)>>>0;h[3]=(h[3]+d)>>>0;h[4]=(h[4]+e)>>>0;h[5]=(h[5]+f)>>>0;h[6]=(h[6]+g)>>>0;h[7]=(h[7]+hh)>>>0;
  }
  return h.map(v=>v.toString(16).padStart(8,'0')).join('');
}
function _strToBytes(s){const b=[];for(let i=0;i<s.length;i++){const c=s.charCodeAt(i);if(c<128)b.push(c);else if(c<2048){b.push((c>>6)|192);b.push((c&63)|128);}else{b.push((c>>12)|224);b.push(((c>>6)&63)|128);b.push((c&63)|128);}}return b;}
function _hexToBytes(hex){const b=[];for(let i=0;i<hex.length;i+=2)b.push(parseInt(hex.slice(i,i+2),16));return b;}
function sha256Hex(input){return _sha256Bytes(typeof input==='string'?_strToBytes(input):input);}
function hmacSha256(keyInput,msgInput){
  let key=typeof keyInput==='string'?_strToBytes(keyInput):[...keyInput];
  const msg=typeof msgInput==='string'?_strToBytes(msgInput):[...msgInput];
  if(key.length>64)key=_hexToBytes(_sha256Bytes(key));
  while(key.length<64)key.push(0);
  const opad=key.map(b=>(b^0x5c)&0xff);
  const ipad=key.map(b=>(b^0x36)&0xff);
  const innerBytes=_hexToBytes(_sha256Bytes([...ipad,...msg]));
  return _hexToBytes(_sha256Bytes([...opad,...innerBytes]));
}
function hmacSha256Hex(keyInput,msgInput){return hmacSha256(keyInput,msgInput).map(b=>b.toString(16).padStart(2,'0')).join('');}
function _extractHost(endpoint) { const withoutProto = endpoint.replace(/^https?:\/\//i, ''); const slashIdx = withoutProto.indexOf('/'); return slashIdx === -1 ? withoutProto : withoutProto.slice(0, slashIdx); }
function _buildQueryString(params) { function pctEncode(str) { return String(str).replace(/[^A-Za-z0-9\-_.~]/g, ch => { const hex = ch.charCodeAt(0).toString(16).toUpperCase(); return '%' + (hex.length === 1 ? '0' + hex : hex); }); } return params.map(([k, v]) => pctEncode(k) + '=' + pctEncode(v)).join('&'); }

function buildPresignedUrl({endpoint, bucket, objectKey, accessKey, secretKey, region, method, expiresIn}) {
  const now = new Date();
  const dateStamp = now.toISOString().slice(0,10).replace(/-/g,'');
  const amzDate   = now.toISOString().replace(/[:-]|\.\d{3}/g,'');
  const host      = _extractHost(endpoint);
  const credentialScope = dateStamp + '/' + region + '/s3/aws4_request';
  const credential      = accessKey + '/' + credentialScope;
  const qsParams = [
    ['X-Amz-Algorithm',       'AWS4-HMAC-SHA256'],
    ['X-Amz-Credential',      credential],
    ['X-Amz-Date',            amzDate],
    ['X-Amz-Expires',         String(expiresIn)],
    ['X-Amz-SignedHeaders',   'host'],
  ];
  const qs = _buildQueryString(qsParams);
  const canonicalRequest = [ method, '/' + bucket + '/' + objectKey, qs, 'host:' + host + '\n', 'host', 'UNSIGNED-PAYLOAD' ].join('\n');
  const canonicalHash = sha256Hex(canonicalRequest);
  const stringToSign  = ['AWS4-HMAC-SHA256', amzDate, credentialScope, canonicalHash].join('\n');
  let sigKey = hmacSha256('AWS4' + secretKey, dateStamp);
  sigKey = hmacSha256(sigKey, region);
  sigKey = hmacSha256(sigKey, 's3');
  sigKey = hmacSha256(sigKey, 'aws4_request');
  const signature = hmacSha256Hex(sigKey, stringToSign);
  return endpoint + '/' + bucket + '/' + objectKey + '?' + qs + '&X-Amz-Signature=' + signature;
}

// --- LOGIC UTAMA: Correction Audio ---
const { session_id } = $input.first().json;

const upload_url = buildPresignedUrl({
  endpoint: $env.MINIO_ENDPOINT,
  bucket: $env.MINIO_BUCKET,
  objectKey: 'audio/' + session_id + '_correction.mp3',
  accessKey: $env.MINIO_ACCESS_KEY,
  secretKey: $env.MINIO_SECRET_KEY,
  region: $env.MINIO_REGION || 'us-east-1',
  method: 'PUT',
  expiresIn: 60
});

return [{
  json: { upload_url },
  binary: $input.first().binary
}];

// ============================================================
// Node: Sanitize Conversation Text for TTS
// Dipanggil dari PUT minIO — Correction (sequential path)
// Baca conversation_text dari Parse Grammar Response, sanitize untuk TTS
// ============================================================
const grammarData = $('Parse Grammar Response').first().json;
let text = (grammarData.conversation_text || '').trim();

// Sanitasi: hapus markdown bold (**word**)
text = text.replace(/\*\*(.*?)\*\*/g, '$1');
// Hapus newline berlebihan, ganti dengan spasi
text = text.replace(/\r?\n+/g, ' ');
// Hapus karakter kontrol
text = text.replace(/[\x00-\x1F\x7F]/g, '');
// Trim spasi berlebih
text = text.replace(/\s{2,}/g, ' ').trim();

// Fallback jika kosong
if (!text) text = 'Let us continue our conversation.';

// Batasi panjang (Grok TTS max ~4096 chars)
if (text.length > 1000) text = text.slice(0, 1000);

return [{
  json: {
    ...grammarData,
    tts_conversation_text: text
  }
}];

// ============================================================
// Node: Build User Profile Response
// Ambil data user dari DB, return name + level + avatar_url
// ============================================================

const rows = $input.all();

if (!rows || rows.length === 0 || !rows[0].json.id) {
  return [{
    json: {
      success: true,
      user: {
        id: $('Webhook — POST /user/profile').first().json.body.user_id,
        name: 'Learner',
        display_name: 'Learner',
        level: 'A1',
        avatar_url: null
      }
    }
  }];
}

const user = rows[0].json;

return [{
  json: {
    success: true,
    user: {
      id:           user.id,
      name:         user.name,
      display_name: user.name,
      level:        user.level || 'A1',
      created_at:   user.created_at,
      // Cek berbagai kemungkinan nama kolom foto di DB
      avatar_url:   user.avatar_url || user.photo_url || user.picture || user.profile_photo || null
    }
  }
}];

// 1. Ambil data utuh dari node sebelumnya
const inputData = $input.first().json;
const rawTopic = inputData.topic || '';

// 2. Cek apakah ini mode latihan kosakata
if (rawTopic.startsWith('Practice vocabulary:')) {
  const cleanText = rawTopic.replace('Practice vocabulary:', '').trim();
  const wordsArray = cleanText.split(',').map(w => w.trim().toLowerCase()).filter(w => w.length > 0);

  // 3. Kita pecah, tapi setiap baris tetap membawa seluruh payload chat agar aman
  return wordsArray.map(word => {
    return {
      json: {
        ...inputData,       // Membawa semua data (correction, conversation_text, minio_url, dll)
        vocab_word: word    // Menyisipkan 1 kata spesifik untuk loop Postgres
      }
    };
  });
}

// Jika bukan mode vocab, teruskan data asli
return [{ json: inputData }];

// ============================================================
// Node: Build Pull Dashboard Response
// Ambil max 20 vocab dengan is_mastered = false
// Return: vocabulary_raw (string comma-separated) + vocab_list (array detail)
// ============================================================

const items = $input.all();

// Filter row kosong (alwaysOutputData bisa return 1 row kosong)
const rows = items
  .map(i => i.json)
  .filter(r => r && r.vocab_word);

if (rows.length === 0) {
  return [{
    json: {
      success: false,
      error: 'No unmastered vocabulary found in dashboard.',
      count: 0,
      vocabulary_raw: '',
      vocab_list: []
    }
  }];
}

// Comma-separated string untuk langsung isi input di HTML
const vocabularyRaw = rows.map(r => r.vocab_word).join(', ');

// Array detail untuk preview chips di UI
const vocabList = rows.map(r => ({
  id:             r.id,
  word:           r.vocab_word,
  part_of_speech: r.part_of_speech || '',
  level:          r.level || '',
  definition:     r.definition || ''
}));

return [{
  json: {
    success: true,
    count: rows.length,
    vocabulary_raw: vocabularyRaw,
    vocab_list: vocabList
  }
}];

// Attach metadata dari webhook ke setiap vocab item
const webhook = $('Vocab Sync Dashboard').first().json;

return items.map(item => ({
  json: {
    word:       item.json.word.trim().toLowerCase(),  // membuat vocab menjadi kecil eg. dog
    achieved:   item.json.achieved ?? false,
    sentence:   item.json.sentence ?? '',
    user_id:    webhook.body.user_id,
    session_id: webhook.body.session_id,
    level:      webhook.body.level ?? 'A1'
  }
}));

// Merge vocabulary_id dari PostgreSQL 1
// dengan achieved + user_id + session_id dari Prepare Item
const prepareItems = $('Prepare Item').all();

return items.map((item, i) => ({
  json: {
    vocabulary_id: item.json.id,
    user_id:       prepareItems[i]?.json?.user_id,
    session_id:    prepareItems[i]?.json?.session_id,
    achieved:      prepareItems[i]?.json?.achieved ?? false
  }
}));

// Hitung summary hasil sync
const allItems = $input.all();
const webhook = $('Vocab Sync Dashboard').first().json.body;

return [{
  json: {
    success: true,
    message: 'Vocab synced successfully',
    user_id:    webhook.user_id,
    session_id: webhook.session_id,
    total_synced: allItems.length,
    synced_at: new Date().toISOString()
  }
}];
